com.mirth.connect.plugins.javascriptstep.script:
var isReplay = channelMap.get('isReplay') == true;
logger.info("RECEIVED MSG: " + msg);
logger.info("RECEIVED RAW: " + connectorMessage.getRawData());
logger.info("RECEIVED isReplay: " + isReplay);
if (isReplay) {
    logger.info("Replaying message...");
    channelMap.put('skipRawInsert', true);
} else {
    channelMap.put('skipRawInsert', false);
}

var patientId = msg['PID']['PID.3']['PID.3.1'].toString();

logger.info("RECEIVED → Patient ID = " + patientId);
logger.info("RECEIVED → hasError BEFORE = " + channelMap.get('hasError'));

if (patientId == '99999') {
    channelMap.put('hasError', true);
    channelMap.put('errorMessage', 'Test error');
} else {
    channelMap.put('hasError', false);
}


logger.info("RECEIVED → hasError AFTER = " + channelMap.get('hasError'));
// =======================
// Utility Functions
// =======================
function safeGet(field) {
    try {
        var value = field.toString();
        return value ? value.trim() : null;
    } catch (e) {
        return null;
    }
}

function formatHL7Date(dateStr) {
    if (!dateStr || dateStr.length < 8) {
        logger.warn("Invalid birthDate: " + dateStr);
        return null;
    }

    return dateStr.substring(0, 4) + '-' +
           dateStr.substring(4, 6) + '-' +
           dateStr.substring(6, 8);
}

function mapGender(gender) {
    if (!gender) return null;

    switch (gender) {
        case 'M': return 'male';
        case 'F': return 'female';
        case 'U': return 'unknown';
        default:
            logger.warn("Unknown gender value: " + gender);
            return 'unknown';
    }
}

// =======================
// Extraction
// =======================

//Store Every Incoming Message
var rawHL7 = connectorMessage.getRawData();
var messageControlId = msg['MSH']['MSH.10']['MSH.10.1'].toString();

channelMap.put('rawHL7', rawHL7);
channelMap.put('messageControlId', messageControlId);

var patient = {};

patient.id = safeGet(msg['PID']['PID.3']['PID.3.1']);
patient.firstName = safeGet(msg['PID']['PID.5']['PID.5.2']);
patient.lastName = safeGet(msg['PID']['PID.5']['PID.5.1']);
patient.birthDateRaw = safeGet(msg['PID']['PID.7']['PID.7.1']);
patient.genderRaw = safeGet(msg['PID']['PID.8']['PID.8.1']);
patient.doctorLastName = safeGet(msg['PV1']['PV1.7']['PV1.7.2']);

// =======================
// Validation
// =======================

if (!patient.id) {
    throw "Missing patient ID";
    var errorMsg = "Missing patient ID (PID.3.1)";

    logger.error(errorMsg);

    // Store error info
    channelMap.put('error', errorMsg);
    channelMap.put('isRejected', true);

    return;
}

if (!patient.lastName) {
	throw "Missing Missing last name";
    logger.warn("Missing last name for patient ID: " + patient.id);
}

// =======================
// Transformation
// =======================

patient.birthDate = formatHL7Date(patient.birthDateRaw);
patient.gender = mapGender(patient.genderRaw);
patient.fullName = (patient.firstName || "") + " " + (patient.lastName || "");

channelMap.put('id', patient.id);
channelMap.put('firstName', patient.firstName);
channelMap.put('lastName', patient.lastName);
channelMap.put('fullName', patient.fullName);
channelMap.put('gender', patient.gender);
channelMap.put('birthDate', patient.birthDate);
channelMap.put('doctor', patient.doctorLastName);

channelMap.put('sourceSystem', msg['MSH']['MSH.4']['MSH.4.1'].toString());
channelMap.put('messageType', msg['MSH']['MSH.9']['MSH.9.1'].toString());
channelMap.put('eventType', msg['MSH']['MSH.9']['MSH.9.2'].toString());
// =======================
// Output JSON
// =======================

var patientJSON = JSON.stringify(patient, null, 2);

// Store for next steps
channelMap.put('patientJSON', patientJSON);
channelMap.put('isRejected', false);
// =======================
// Logging
// =======================

logger.info("=== TRANSFORMED PATIENT ===");
logger.info(patientJSON);

properties.query:
UPDATE RawMessages
SET Status = 'ERROR',
    ErrorMessage = ${errorMessage}
WHERE MessageControlId = ${messageControlId}

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
